using UnityEngine;
using System.Text;
public class Script
{
    public static object Main()
    {
        var sb = new StringBuilder();
        // 通过 ClientDataCenter 获取背包数据
        try {
            var items = FL.ClientDataModule.ClientDataCenter.BackpackData;
            if (items == null) return "BackpackData is null";
            sb.AppendLine("Backpack items:");
            foreach (var kv in items.DictItemNum)
            {
                sb.AppendLine("  cfgId=" + kv.Key + " qty=" + kv.Value);
            }
            if (sb.Length < 20) sb.AppendLine("  (empty)");
            return sb.ToString();
        } catch (System.Exception e) { return "Error: " + e.Message; }
    }
}
